#!/usr/bin/env python3
"""Parse official and MCN Markdown reports, then print dual-platform stats as JSON."""
from __future__ import annotations

import json
import re
from pathlib import Path


WORKSPACE = Path(__file__).resolve().parents[1]
XIAOHONGSHU_FILE = WORKSPACE / "xiaohongshu-analytics-export.md"
BILIBILI_FILE = WORKSPACE / "bilibili-analytics.md"
MCN_FILE = WORKSPACE / "mcn-brand-report.md"


def markdown_text(path: Path) -> str:
    if not path.exists():
        raise FileNotFoundError(f"Missing required file: {path}")
    return path.read_text(encoding="utf-8")


def to_int(number_text: str) -> int:
    return int(number_text.strip().replace(",", ""))


def table_value(markdown: str, label: str) -> int:
    pattern = rf"^\|\s*{re.escape(label)}\s*\|\s*([\d,]+)\s*\|\s*$"
    match = re.search(pattern, markdown, flags=re.MULTILINE)
    if not match:
        raise ValueError(f"Could not find Markdown table row for {label!r}")
    return to_int(match.group(1))


def section(markdown: str, heading: str) -> str:
    pattern = rf"^###\s+{re.escape(heading)}\s*$\n(?P<body>.*?)(?=^###\s+|^##\s+|\Z)"
    match = re.search(pattern, markdown, flags=re.MULTILINE | re.DOTALL)
    if not match:
        raise ValueError(f"Could not find section {heading!r}")
    return match.group("body")


def main() -> None:
    xiaohongshu_markdown = markdown_text(XIAOHONGSHU_FILE)
    bilibili_markdown = markdown_text(BILIBILI_FILE)
    mcn_markdown = markdown_text(MCN_FILE)

    xiaohongshu_official = table_value(xiaohongshu_markdown, "播放量")
    bilibili_official = table_value(bilibili_markdown, "播放量")

    xiaohongshu_mcn = table_value(section(mcn_markdown, "小红书平台"), "视频播放量")
    bilibili_mcn = table_value(section(mcn_markdown, "bilibili 平台"), "视频播放量")

    xiaohongshu_ratio = xiaohongshu_mcn / xiaohongshu_official
    bilibili_ratio = bilibili_mcn / bilibili_official
    average_ratio = (xiaohongshu_ratio + bilibili_ratio) / 2

    result = {
        "xiaohongshu_official": xiaohongshu_official,
        "xiaohongshu_mcn": xiaohongshu_mcn,
        "bilibili_official": bilibili_official,
        "bilibili_mcn": bilibili_mcn,
        "xiaohongshu_ratio": xiaohongshu_ratio,
        "bilibili_ratio": bilibili_ratio,
        "average_ratio": average_ratio,
        "all_above_2x": xiaohongshu_ratio > 2 and bilibili_ratio > 2,
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

